import React from "react";

export default function AlertBanner({ state = "NORMAL", confidence = 0 }) {
  if (state !== "ATTACK") {
    return (
      <div className="bg-green-100 border border-green-400 text-green-800 px-4 py-3 rounded mb-4">
        ✅ System state: NORMAL
      </div>
    );
  }

  return (
    <div className="bg-red-100 border border-red-400 text-red-800 px-4 py-3 rounded mb-4">
      🚨 Attack detected ({(Number(confidence || 0) * 100).toFixed(1)}% confidence)
    </div>
  );
}